import json
from typing import Union


def flatten_ec2_metadata(data: Union[dict, str], max_depth: int = 20) -> dict:
    """
    Convert AWS EC2 instance metadata JSON response into a flattened dictionary with dot-notation keys.

    Parameters:
        data (Union[dict, str]): Either a pre-parsed dict or a raw JSON string.
        max_depth (int): Maximum recursion depth allowed. Default is 20.

    Returns:
        dict: A flat dictionary where nested keys are joined with dot-notation.

    Raises:
        ValueError: If input is None or not a dict or str type.
        ValueError: If a JSON string cannot be parsed by json.loads().
        ValueError: If recursion depth reaches max_depth.

    The dot-notation key format joins nested keys with '.', and list indices are
    converted to strings (e.g., 'network.interfaces.0.mac').

    Example:
        >>> metadata = {
        ...     "instanceId": "i-1234567890abcdef0",
        ...     "network": {
        ...         "interfaces": [
        ...             {"mac": "02:42:ac:11:00:02", "privateIp": "172.17.0.2"}
        ...         ]
        ...     }
        ... }
        >>> flatten_ec2_metadata(metadata)
        {'instanceId': 'i-1234567890abcdef0', 'network.interfaces.0.mac': '02:42:ac:11:00:02', 'network.interfaces.0.privateIp': '172.17.0.2'}
    """
    if data is None or not isinstance(data, (dict, str)):
        raise ValueError("Input must be a dict or a JSON string, not None or other types.")

    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Failed to parse JSON string: {e}")

    if not isinstance(data, dict):
        return {"": data}

    def _flatten(obj, prefix, depth):
        if depth >= max_depth:
            raise ValueError(f"Recursion depth limit of {max_depth} reached.")
        items = {}
        if isinstance(obj, dict):
            for k, v in obj.items():
                new_key = prefix + "." + k if prefix else k
                items.update(_flatten(v, new_key, depth + 1))
        elif isinstance(obj, list):
            for i, v in enumerate(obj):
                new_key = prefix + "." + str(i) if prefix else str(i)
                items.update(_flatten(v, new_key, depth + 1))
        else:
            items[prefix] = obj
        return items

    return _flatten(data, "", 0)

import re

AWS_KEY_PATTERN = re.compile(
    r'\b((?:AKIA|ASIA|AROA|AIDA)[A-Z0-9]{16})\b',
    re.ASCII  # enforce ASCII-only matching; prevents Unicode word chars from affecting \b and ensures case-sensitive behavior
)

def extract_aws_keys(text):
    return AWS_KEY_PATTERN.findall(text)

from typing import Any


def filter_dynamodb_items(
    items: list[dict],
    attribute_name: str,
    condition_value: Any,
) -> list[dict]:
    """
    Filter DynamoDB items based on a simple attribute condition.

    Parameters:
        items: List of DynamoDB item dicts in boto3 typed format.
        attribute_name: The attribute name to filter on.
        condition_value: The plain Python value to compare against.

    Returns:
        List of items where the attribute matches the condition value.

    Raises:
        ValueError: If items is None or contains non-dict elements.
        ValueError: If attribute_name is None, not a string, or empty.
        ValueError: If an unsupported DynamoDB type is encountered.
    """
    if items is None:
        raise ValueError("items must not be None")
    if not all(isinstance(item, dict) for item in items):
        raise ValueError("All elements in items must be dicts")
    if attribute_name is None or not isinstance(attribute_name, str) or attribute_name == "":
        raise ValueError("attribute_name must be a non-empty string")

    def extract(typed_value: dict) -> Any:
        for type_key, val in typed_value.items():
            if type_key == "S":
                return val
            elif type_key == "N":
                return float(val)
            elif type_key == "BOOL":
                return val
            else:
                raise ValueError(f"Unsupported DynamoDB type: {type_key}")

    def matches(item: dict) -> bool:
        if attribute_name not in item:
            return False
        extracted = extract(item[attribute_name])
        cmp = float(condition_value) if isinstance(extracted, float) else condition_value
        return extracted == cmp

    return [item for item in items if matches(item)]

def calculate_s3_cost(size_bytes, storage_class):
    # Pricing constants last verified against AWS public pricing: 2024-01-01
    STANDARD_TIERS = [(50 * 1024**4, 0.023), (450 * 1024**4, 0.022), (float('inf'), 0.021)]
    RATES = {
        'STANDARD': None,
        'STANDARD_IA': 0.0125,
        'ONEZONE_IA': 0.01,
        'INTELLIGENT_TIERING': 0.023,
        'GLACIER': 0.004,
        'GLACIER_DEEP_ARCHIVE': 0.00099,
        'GLACIER_INSTANT_RETRIEVAL': 0.004,
    }
    GB = 1024 ** 3
    KB128 = 128 * 1024
    KB40 = 40 * 1024
    KB8 = 8 * 1024

    if size_bytes < 0:
        raise ValueError("size_bytes must be non-negative")
    if storage_class not in RATES:
        raise ValueError(f"Unrecognized storage_class: {storage_class}")

    if storage_class == 'STANDARD':
        cost = 0.0
        remaining = size_bytes
        prev = 0
        for tier_limit, rate in STANDARD_TIERS:
            tier_size = min(remaining, tier_limit - prev)
            if tier_size <= 0:
                break
            cost += tier_size * rate / GB
            remaining -= tier_size
            prev = tier_limit
            if remaining <= 0:
                break
        return round(cost, 10)

    elif storage_class in ('STANDARD_IA', 'ONEZONE_IA'):
        billable = max(size_bytes, KB128)
        cost = billable * RATES[storage_class] / GB * (30 / 30)
        return round(cost, 10)

    elif storage_class == 'GLACIER_INSTANT_RETRIEVAL':
        billable = max(size_bytes, KB128)
        cost = billable * RATES[storage_class] / GB * (90 / 30) / (90 / 30)
        return round(cost, 10)

    elif storage_class == 'GLACIER':
        billable = max(size_bytes, KB40) + KB8
        cost = billable * RATES[storage_class] / GB * (90 / 30) / 3
        return round(cost, 10)

    elif storage_class == 'GLACIER_DEEP_ARCHIVE':
        billable = max(size_bytes, KB40)
        cost = billable * RATES[storage_class] / GB * (180 / 30) / 6
        return round(cost, 10)

    elif storage_class == 'INTELLIGENT_TIERING':
        # Assumes 100% frequent access tier by default
        storage_cost = size_bytes * RATES[storage_class] / GB
        monitoring_fee = 0.0025 / 1000
        cost = storage_cost + monitoring_fee
        return round(cost, 10)
